import os
import sys


def calculate_average(numbers):
    """计算数字列表的平均值"""
    if not numbers:
        return 0
    return sum(numbers) / len(numbers)


def process_data(data, options, config, settings, parameters):
    # 这个函数参数过多，且缺少文档字符串
    result = []
    for item in data:
        if options.get('enabled', True):
            if config.get('mode') == 'fast':
                if settings.get('validate'):
                    if parameters.get('strict'):
                        if item.get('value') > 0:
                            result.append(item)
                    else:
                        if item.get('value') >= 0:
                            result.append(item)
                else:
                    result.append(item)
            else:
                if settings.get('validate'):
                    if parameters.get('strict'):
                        if item.get('value') > 10:
                            result.append(item)
                    else:
                        if item.get('value') >= 10:
                            result.append(item)
                else:
                    result.append(item)
        else:
            if item.get('important'):
                result.append(item)
    return result


