class DataProcessor:
    """数据处理类"""

    def __init__(self):
        self.data = []

    def load_data(self, filepath):
        """加载数据"""
        with open(filepath, 'r') as f:
            self.data = f.readlines()

    def process(self):
        """处理数据"""
        results = []
        for line in self.data:
            if line.strip():
                results.append(line.strip())
        return results

    def save(self, filepath):
        """保存数据"""
        with open(filepath, 'w') as f:
            f.writelines(self.data)


